2383: void RestyleManager::PostRestyleEvent(Element* aElement,
2384:                                       RestyleHint aRestyleHint,
2385:                                       nsChangeHint aMinChangeHint) {
2386:   MOZ_ASSERT(!(aMinChangeHint & nsChangeHint_NeutralChange),
2387:              "Didn't expect explicit change hints to be neutral!");
2388:   if (MOZ_UNLIKELY(IsDisconnected()) ||
2389:       MOZ_UNLIKELY(PresContext()->PresShell()->IsDestroying())) {
2390:     return;
2391:   }
2392: 
2393:   // We allow posting restyles from within change hint handling, but not from
2394:   // within the restyle algorithm itself.
2395:   MOZ_ASSERT(!ServoStyleSet::IsInServoTraversal());
2396: 
2397:   if (!aRestyleHint && !aMinChangeHint) {
2398:     // FIXME(emilio): we should assert against this instead.
2399:     return;  // Nothing to do.
2400:   }
2401: 
2402:   // Assuming the restyle hints will invalidate cached style for
2403:   // getComputedStyle, since we don't know if any of the restyling that we do
2404:   // would affect undisplayed elements.
2405:   if (aRestyleHint) {
2406:     if (!(aRestyleHint & RestyleHint::ForAnimations())) {
2407:       mHaveNonAnimationRestyles = true;
2408:     }
2409: 
2410:     IncrementUndisplayedRestyleGeneration();
2411:   }
2412: 
2413:   // Processing change hints sometimes causes new change hints to be generated,
2414:   // and very occasionally, additional restyle hints. We collect the change
2415:   // hints manually to avoid re-traversing the DOM to find them.
2416:   if (mReentrantChanges && !aRestyleHint) {
2417:     mReentrantChanges->AppendElement(ReentrantChange{aElement, aMinChangeHint});
2418:     return;
2419:   }
2420: 
2421:   if (aRestyleHint || aMinChangeHint) {
2422:     Servo_NoteExplicitHints(aElement, aRestyleHint, aMinChangeHint);
2423:   }
2424: }
